from flask import Flask, request, jsonify
import jwt
from jwt import ExpiredSignatureError, InvalidTokenError

app = Flask(__name__)

class JWTWrapper:
    def __init__(self):
        self.algorithms = {
            "HS256": {"key": "your_hs256_secret_key", "algorithm": "HS256"},
            "RS256": {"key": self.load_rsa_public_key("path_to_public_key.pem"), "algorithm": "RS256"}
        }

    def load_rsa_public_key(self, filepath):
        with open(filepath, "r") as file:
            return file.read()

    def decode_jwt(self, token, algorithm_type):
        try:
            options = self.algorithms.get(algorithm_type)
            if not options:
                raise ValueError("Unsupported algorithm type")
            payload = jwt.decode(token, options['key'], algorithms=[options['algorithm']])
            return payload
        except ExpiredSignatureError:
            return {"error": "Token has expired"}
        except InvalidTokenError:
            return {"error": "Invalid token"}
        except Exception as e:
            return {"error": str(e)}

@app.route('/verify', methods=['POST'])
def verify_token():
    data = request.json
    token = data.get('token')
    algorithm_type = data.get('algorithm_type')
    jwt_wrapper = JWTWrapper()
    result = jwt_wrapper.decode_jwt(token, algorithm_type)
    return jsonify(result)

